using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Provides web search capabilities to the research agent.
/// Uses a simulated search engine for demonstration purposes.
/// Replace the implementation with a real search API (e.g., Bing Search) for production use.
/// </summary>
public sealed class WebSearchTool
{
    private static readonly Dictionary<string, List<SearchResult>> SimulatedResults = new(StringComparer.OrdinalIgnoreCase)
    {
        ["quantum computing"] =
        [
            new("Quantum Computing Fundamentals",
                "Quantum computing leverages quantum mechanical phenomena such as superposition and entanglement to process information. Unlike classical bits, qubits can exist in multiple states simultaneously, enabling exponential parallelism for certain problem classes.",
                "https://example.com/quantum-fundamentals"),
            new("Recent Advances in Quantum Hardware",
                "In 2025, several companies achieved significant milestones: IBM unveiled its 1,121-qubit Condor processor, Google demonstrated quantum error correction at scale, and startups like PsiQuantum advanced photonic quantum computing approaches.",
                "https://example.com/quantum-hardware-2025"),
            new("Quantum Computing Applications",
                "Key application areas include cryptography (Shor's algorithm for factoring), optimization (QAOA for combinatorial problems), drug discovery (molecular simulation), and machine learning (quantum kernel methods). Commercial quantum advantage remains limited to specific problem domains.",
                "https://example.com/quantum-applications"),
        ],
        ["artificial intelligence"] =
        [
            new("State of AI in 2025",
                "AI has evolved rapidly with large language models, multimodal systems, and agentic workflows becoming mainstream. Key trends include smaller, more efficient models, on-device inference, and increasing focus on safety and alignment research.",
                "https://example.com/ai-state-2025"),
            new("AI in Healthcare",
                "AI-driven diagnostics, drug discovery, and personalized treatment plans are transforming healthcare. FDA-approved AI tools now assist in radiology, pathology, and genomic analysis with accuracy matching or exceeding human specialists.",
                "https://example.com/ai-healthcare"),
            new("Ethical Considerations in AI",
                "Major concerns include algorithmic bias, job displacement, privacy, and the concentration of AI capabilities. Regulatory frameworks like the EU AI Act are being implemented to govern high-risk AI applications.",
                "https://example.com/ai-ethics"),
        ],
    };

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public static IReadOnlyList<SearchResult> Search(
        [Description("The search query to look up on the web")] string query)
    {
        // Check for exact key matches first
        if (SimulatedResults.TryGetValue(query, out var results))
        {
            return results;
        }

        // Fall back to partial keyword matching
        foreach (var (key, value) in SimulatedResults)
        {
            if (query.Contains(key, StringComparison.OrdinalIgnoreCase)
                || key.Contains(query, StringComparison.OrdinalIgnoreCase))
            {
                return value;
            }
        }

        return
        [
            new("General Research Result",
                $"Information about '{query}': This is a broad topic with many facets. "
                + "Key areas of study include theoretical foundations, practical applications, "
                + "and ongoing research developments. Experts recommend consulting academic "
                + "journals and reputable sources for the most current information.",
                $"https://example.com/search?q={Uri.EscapeDataString(query)}")
        ];
    }
}

public sealed record SearchResult(string Title, string Snippet, string Url);

using System.ComponentModel;

namespace ResearchAgent;

/// <summary>
/// Provides note-taking capabilities for the research agent.
/// The agent can save, list, and retrieve notes to build up research findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a topic label and detailed content. Use this to record important findings from web searches.")]
    public string SaveNote(
        [Description("A short label or topic for the note")] string topic,
        [Description("The detailed content of the note")] string content,
        [Description("The source URL where this information was found")] string sourceUrl)
    {
        var note = new Note(topic, content, sourceUrl, DateTime.UtcNow);
        _notes.Add(note);
        return $"Note saved: '{topic}' ({_notes.Count} total notes)";
    }

    [Description("Returns all saved research notes collected so far.")]
    public IReadOnlyList<Note> GetAllNotes()
    {
        return _notes.AsReadOnly();
    }

    [Description("Returns the total number of notes saved so far.")]
    public int GetNoteCount()
    {
        return _notes.Count;
    }
}

public sealed record Note(string Topic, string Content, string SourceUrl, DateTime SavedAt);

