using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Service registration ---
var services = new ServiceCollection();

services.AddLogging(builder => builder
    .AddConsole()
    .SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseFunctionInvocation()
    .UseOpenAIChatClient(modelId, apiKey));

services.AddSingleton<NoteTakingTool>();

var provider = services.BuildServiceProvider();
var chatClient = provider.GetRequiredService<IChatClient>();
var noteTool = provider.GetRequiredService<NoteTakingTool>();

// --- Tool registration ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.Search),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetAllNotes),
    AIFunctionFactory.Create(noteTool.GetNoteCount),
};

// --- Agent setup ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. Your job is to research a given topic thoroughly
        and produce a well-organized summary.

        Follow this workflow:
        1. Search the web for information on the topic.
        2. For each relevant result, save a note with the key findings using SaveNote.
        3. After collecting enough notes (at least 3), retrieve all notes with GetAllNotes.
        4. Synthesize the notes into a clear, structured summary with sections and source citations.

        Always cite your sources using the URLs from search results.
        Be thorough but concise in your final summary.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Run the agent ---
var topic = args.Length > 0 ? string.Join(' ', args) : "quantum computing";
Console.WriteLine($"🔍 Researching: {topic}\n");

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}");

foreach (var message in response.Messages)
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.WriteLine(message.Text);
    }
}

Console.WriteLine($"\n📝 Total notes collected: {noteTool.GetNoteCount()}");
Console.WriteLine("✅ Research complete.");

